DELIMITER $$
CREATE TRIGGER `Mise_solde` BEFORE INSERT ON `congé` FOR EACH ROW BEGIN
    UPDATE praticien p
    SET p.Solde_congé = p.Solde_congé - (DATEDIFF(NEW.date_fin, NEW.date_debut) + 1)
    WHERE p.id = NEW.ID_praticien$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `insert_mess-auto` BEFORE UPDATE ON `congé` FOR EACH ROW BEGIN

  IF (NEW.état = '2') THEN
    VALUES (
      7,
      NEW.Id_praticien,
      CONCAT(
        'Congé accepté du : ',
        DATE_FORMAT(OLD.date_debut, '%d/%m/%Y'),
        ' au ',
        DATE_FORMAT(OLD.date_fin, '%d/%m/%Y')
      ),
      2
    )$$
